## Implementation Approach
```javascript
// Cloud Function: validate JSONL lines
const { Storage } = require('@google-cloud/storage');
const { PubSub } = require('@google-cloud/pubsub');

exports.validateLogs = async (event, context) => {
  const storage = new Storage();
  const pubsub = new PubSub();
  const bucket = storage.bucket(event.bucket);
  const file = bucket.file(event.name);

  const contents = await file.download();
  const lines = contents.toString().split('\n').filter(line => line.trim());

  const validRecords = [];
  const invalidLines = [];

  lines.forEach((line, index) => {
    try {
      const record = JSON.parse(line);
      const required = ['event_id', 'device_id', 'ts', 'event_type'];

      if (required.every(field => record[field])) {
        validRecords.push({ data: Buffer.from(JSON.stringify(record)) });
      } else {
        invalidLines.push({ line, error: 'Missing required fields', lineNumber: index });
      }
    } catch (error) {
      invalidLines.push({ line, error: 'Invalid JSON', lineNumber: index });
    }
  });

  // Publish valid records
  if (validRecords.length > 0) {
    await pubsub.topic('app-logs.events').publish(validRecords);
  }

  // Move invalid lines to dead-letter bucket
  if (invalidLines.length > 0) {
    const invalidContent = invalidLines.map(item => 
      JSON.stringify({ ...item, timestamp: new Date().toISOString() })
    ).join('\n');

    await storage.bucket('app-logs-invalid')
      .file(`invalid/${event.name}`)
      .save(invalidContent);
  }

  // Move processed file
  await file.move('processed/' + event.name);
};
```

```python
# Dataflow streaming job
import apache_beam as beam
from apache_beam.options.pipeline_options import PipelineOptions

class ProcessLogRecord(beam.DoFn):
    def process(self, element):
        import json
        record = json.loads(element.decode('utf-8'))

        yield {
            'event_id': record['event_id'],
            'device_id': record['device_id'],
            'ts': record['ts'],
            'event_type': record['event_type'],
            'insertId': record['event_id']
        }

def run():
    options = PipelineOptions([
        '--project=your-project',
        '--region=us-central1',
        '--streaming',
        '--temp_location=gs://your-temp/temp'
    ])

    with beam.Pipeline(options=options) as p:
        (p 
         | 'ReadFromPubSub' >> beam.io.ReadFromPubSub(
             subscription='projects/your-project/subscriptions/app-logs-sub')
         | 'ProcessRecords' >> beam.ParDo(ProcessLogRecord())
         | 'WriteToBigQuery' >> beam.io.WriteToBigQuery(
             'analytics.app_logs',
             schema='event_id:STRING,device_id:STRING,ts:TIMESTAMP,event_type:STRING',
             write_disposition=beam.io.BigQueryDisposition.WRITE_APPEND,
             create_disposition=beam.io.BigQueryDisposition.CREATE_IF_NEEDED,
             insert_id_strategy='USE_FIELD',
             insert_id_field_name='insertId'))
```

