## Code Example

```javascript
// telemetry-processor/index.js
const {Storage} = require('@google-cloud/storage');
const {BigQuery} = require('@google-cloud/bigquery');
const storage = new Storage();
const bigquery = new BigQuery();
const sanitizedBucket = process.env.SANITIZED_BUCKET;

exports.telemetryProcessor = async (event, context) => {
  const raw = Buffer.from(event.data, 'base64').toString();
  let obj = JSON.parse(raw);
  // redact common PII
  ['ssn','email','phone','card'].forEach(k => { if (obj[k]) obj[k] = 'REDACTED'; });
  const bucket = storage.bucket(sanitizedBucket);
  const name = `${obj.id || context.eventId}.json`;
  await bucket.file(name).save(JSON.stringify(obj));
  // BigQuery insert (pseudo): await bigquery.insert({ ... }, { insertId: `${name}` });
};
```

