## Code Example

```javascript
// Example Cloud Function skeleton (Node.js)
const {BigQuery} = require('@google-cloud/bigquery');
const crypto = require('crypto');
const bigquery = new BigQuery();

exports.incomingLogs = async (message, context) => {
  let data;
  try {
    data = JSON.parse(Buffer.from(message.data, 'base64').toString());
  } catch (e) {
    console.error('Invalid JSON');
    return;
  }
  const required = ['service','level','timestamp','message'];
  if (!required.every(k => data.hasOwnProperty(k))) {
    console.error('Missing fields');
    return;
  }
  const sign = data.service + data.timestamp + data.message;
  const insertId = crypto.createHash('md5').update(sign).digest('hex');
  const row = {
    insertId,
    service: data.service,
    level: data.level,
    timestamp: data.timestamp,
    message: data.message
  };
  await bigquery.dataset('analytics').table('logs').insert(row);
};
```

## Follow-up Questions

- How would you handle schema evolution and new fields?
- How would you monitor failure rates and poison messages?

## Why This Is Asked
