```javascript
const { BigQuery } = require('@google-cloud/bigquery');
const { PubSub } = require('@google-cloud/pubsub');

const bigquery = new BigQuery();
const pubsub = new PubSub();

const REQUIRED_FIELDS = ['deviceId', 'ts', 'reading'];
const DATASET = 'iot';
const TABLE = 'telemetry';
const DLQ_TOPIC = 'iot-telemetry-dlq';

exports.handleTelemetry = async (message, context) => {
  const data = JSON.parse(Buffer.from(message.data, 'base64').toString());

  const missingFields = REQUIRED_FIELDS.filter(field => !data[field]);

  if (missingFields.length > 0) {
    await pubsub.topic(DLQ_TOPIC).publishMessage({
      data: Buffer.from(JSON.stringify({ ...data, error: `Missing fields: ${missingFields.join(', ')}` })).toString('base64')
    });
    return;
  }

  const insertId = `${data.deviceId}_${data.ts}`;

  await bigquery.dataset(DATASET).table(TABLE).insert([data], { insertId });
};
```

