## Code Example

```javascript
// Cloud Function: validate-events
const { Storage } = require('@google-cloud/storage');
const { BigQuery } = require('@google-cloud/bigquery');
const crypto = require('crypto');

const storage = new Storage();
const bigquery = new BigQuery();

exports.validateEvents = async (event, context) => {
  const fileName = context.eventId;
  const bucketName = event.bucket;

  // Download and validate file
  const file = storage.bucket(bucketName).file(fileName);
  const contents = await file.download();
  const records = JSON.parse(contents.toString());

  const validRecords = [];
  const invalidRecords = [];

  // Validate each record against JSON Schema
  for (const record of records) {
    if (validateRecord(record)) {
      validRecords.push(record);
    } else {
      invalidRecords.push(record);
    }
  }

  // Write valid records to BigQuery
  if (validRecords.length > 0) {
    const writeId = generateDeterministicId(fileName, new Date());
    await writeToBigQuery(validRecords, writeId);
  }

  // Move invalid files to quarantine
  if (invalidRecords.length > 0) {
    await moveToQuarantine(file, invalidRecords);
  }
};

function generateDeterministicId(fileName, date) {
  const hash = crypto.createHash('md5').update(fileName).digest('hex');
  return `${date.toISOString().split('T')[0]}_${hash}`;
}

function validateRecord(record) {
  // Simple JSON Schema validation
  const schema = {
    type: 'object',
    required: ['id', 'timestamp', 'event_type'],
    properties: {
      id: { type: 'string' },
      timestamp: { type: 'string', format: 'date-time' },
      event_type: { type: 'string' }
    }
  };

  return validateAgainstSchema(record, schema);
}

async function writeToBigQuery(records, writeId) {
  const dataset = bigquery.dataset('events_dataset');
  const table = dataset.table('events_table');

  const rows = records.map(record => ({
    ...record,
    write_id: writeId,
    partition_date: new Date().toISOString().split('T')[0]
  }));

  await table.insert(rows);
}

async function moveToQuarantine(file, invalidRecords) {
  const quarantineBucket = storage.bucket('events-quarantine');
  await file.move(quarantineBucket.file(file.name));

  // Send Pub/Sub notification
  const pubsub = new PubSub();
  await pubsub.topic('validation-failures').publish(Buffer.from(JSON.stringify({
    file: file.name,
    invalidCount: invalidRecords.length,
    timestamp: new Date().toISOString()
  })));
}
```

