Implement a Dataflow streaming job using Apache Beam with the following components:

```java
// State & Timer imports for deduplication
import org.apache.beam.sdk.state.*;
import org.apache.beam.sdk.transforms.windowing.*;
import org.apache.beam.sdk.values.*;

public class IoTTelemetryPipeline {
    public static void main(String[] args) {
        PipelineOptions options = PipelineOptionsFactory.fromArgs(args).create();
        Pipeline pipeline = Pipeline.create(options);

        PCollection<TelemetryEvent> events = pipeline
            .apply("ReadFromPubSub", PubsubIO.readStrings()
                .withTimestampAttribute("ts")
                .withDeadLetterConfiguration(
                    PubsubIO.Write.defaultDeadLetterQueueWithRetryPolicy(
                        PubsubIO.writeStrings()
                            .to(options.getDeadLetterTopic())
                            .withTimestampAttribute("errorTs"),
                    PubsubIO.Write.RetryPolicy.retryForever()
                        .withBackoff(
                            Duration.millis(500), Duration.millis(500), 2.0, Duration.millis(60000))))
                .withMaxBatchSize(100)
                .withMaxBatchDuration(Duration.millis(100)))
            .apply("ParseJSON", ParDo.of(new ParseTelemtryDoFn()));

        // Stateful deduplication by eventId with TTL
        PCollection<TelemetryEvent> dedupedEvents = events
            .apply("DedupByEventId", ParDo.of(new DedupDoFn()));

        // Per-device 1-minute windowed aggregations
        PCollection<DeviceAggregate> aggregates = dedupedEvents
            .apply("AddTimestamp", WithTimestamps.of(e -> Instant.ofEpochMilli(e.getTs())))
            .apply("FixedWindows", Window.into(FixedWindows.of(Duration.standardMinutes(1))))
            .apply("PerDeviceAggregate", Combine.perKey(
                new DeviceAggregateCombiner()))
            .apply("FormatForBigQuery", ParDo.of(new FormatAggregateDoFn()));

        // Write to BigQuery with insertId for idempotency
        aggregates.apply("WriteToBigQuery", BigQueryIO.write()
            .to(options.getOutputTable())
            .withSchema(getSchema())
            .withCreateDisposition(CreateDisposition.CREATE_NEVER)
            .withWriteDisposition(WriteDisposition.WRITE_APPEND)
            .withInsertId("eventId")  // Enables BigQuery deduplication
            .withFailedInsertRetryPolicy(InsertRetryPolicy.retryTransientErrors()));

        pipeline.run();
    }

    // Stateful dedup with 10-minute TTL
    static class DedupDoFn extends DoFn<TelemetryEvent, TelemetryEvent> {
        private static final Duration TTL = Duration.standardMinutes(10);

        @StateId("seenEvents")
        private final StateSpec<Map<String, Instant>> seenEventsSpec =
            StateSpecs.map(ValueStateDescriptor.class);

        @TimerId("expiryTimer")
        private final TimerSpec expiryTimer = TimerSpecs.timer(TimeDomain.EVENT_TIME);

        @ProcessElement
        public void process(
                @Element TelemetryEvent event,
                @State("seenEvents") Map<String, Instant> seenEvents,
                @Timer("expiryTimer") Timer timer) {
            Instant now = Instant.now();
            if (!seenEvents.containsKey(event.getEventId())) {
                seenEvents.put(event.getEventId(), now);
                timer.withOutputTimestamp(now).set(TTL);
                yield PCollection.<TelemetryEvent>PK.of(event);
            }
        }

        @OnTimer("expiryTimer")
        public void onExpiry(
                @State("seenEvents") Map<String, Instant> seenEvents,
                OnTimerContext context) {
            // Cleanup expired entries based on timer
        }
    }

    // Combiner for avg temp and max humidity
    static class DeviceAggregateCombiner 
            extends Combine.CombineFn<TelemetryEvent, DeviceAccumulator, DeviceAggregate> {

        @Override
        public DeviceAccumulator createAccumulator() {
            return new DeviceAccumulator();
        }

        @Override
        public DeviceAccumulator addInput(DeviceAccumulator acc, TelemetryEvent input) {
            acc.sumTemp += input.getTemp();
            acc.maxHumidity = Math.max(acc.maxHumidity, input.getHumidity());
            acc.count++;
            return acc;
        }

        @Override
        public DeviceAggregate extractOutput(DeviceAccumulator acc) {
            return new DeviceAggregate(
                acc.deviceId,
                acc.sumTemp / acc.count,
                acc.maxHumidity,
                Instant.now());
        }
    }

    static TableSchema getSchema() {
        return TableSchema.of(
            TableFieldSchema.ofString("deviceId"),
            TableFieldSchema.ofFloat("avgTemp"),
            TableFieldSchema.ofFloat("maxHumidity"),
            TableFieldSchema.ofTimestamp("windowStart"),
            TableFieldSchema.ofInteger("sampleCount"),
            // Nullable fields for schema evolution
            TableFieldSchema.ofFloat("avgHumidity").setMode(TableFieldSchema.Mode.NULLABLE),
            TableFieldSchema.ofString("metadata").setMode(TableFieldSchema.Mode.NULLABLE));
    }
}

class TelemetryEvent {
    String deviceId, eventId;
    long ts;
    double temp, humidity;
}

class DeviceAccumulator {
    String deviceId;
    double sumTemp;
    double maxHumidity = Double.MIN_VALUE;
    int count;
}

class DeviceAggregate {
    String deviceId, eventId;
    double avgTemp, maxHumidity;
    Instant windowStart;
    int sampleCount;
}
```

**Schema Evolution Strategy:**
- Use BigQuery NULLABLE modes for new fields
- Never remove columns; deprecate by ignoring them in queries
- Add prefixed columns (e.g., `temp_v2`) for breaking changes
- Use Avro schemas with backward-compatible evolution for Dataflow

**Dead-Letter Pattern:**
- Pub/Sub DLQ receives failed messages with error metadata
- Cloud Function processes DLQ for alerting/reprocessing
- Implement exponential backoff retry with 1min max delay

