## Code Example
```javascript
exports.validateTelemetry = async (file, context) => {
  const bucket = storage.bucket(file.bucket);
  const [contents] = await bucket.file(file.name).download();
  const lines = contents.toString().split('\n').filter(l => l.trim());

  const validated = [], quarantined = [];
  const date = new Date().toISOString().split('T')[0].replace(/-/g, '/');

  for (const line of lines) {
    try {
      const record = JSON.parse(line);
      if (!ALLOWED_VERSIONS.includes(record.schemaVersion) || !record.requiredField) {
        throw new Error('Invalid schema');
      }
      validated.push(record);
    } catch (e) {
      quarantined.push(line);
    }
  }

  if (validated.length) {
    const destBucket = storage.bucket('telemetry-validated');
    await destBucket.file(`${date}/${file.name}`).save(JSON.stringify(validated));
    await bigquery.dataset('telemetry').table('events').insert(validated.map(r => ({
      ...r,
      insertId: `${file.name}${date}`
    })));
  }

  if (quarantined.length) {
    const quarBucket = storage.bucket('telemetry-quarantine');
    await quarBucket.file(`${date}/${file.name}`).save(quarantined.join('\n'));
    await pubsub.topic('telemetry-alerts').publish(Buffer.from(JSON.stringify({
      file: file.name,
      quarantinedCount: quarantined.length
    })));
  }
};
```

