// Pseudo-DoFn outline for deduplication and masking
class DeduplicateAndMask extends DoFn<KV<String, String>, TableRow> {
  private Map<String, Instant> seen = new HashMap<>();

  @ProcessElement
  public void process(ProcessContext c) {
    String tenantId = c.element().getKey();
    String eventId = c.element().getValue();
    String dedupKey = tenantId + "-" + eventId;

    if (!seen.containsKey(dedupKey) || 
        seen.get(dedupKey).plus(Duration.standardHours(24)).isBeforeNow()) {
      seen.put(dedupKey, Instant.now());
      TableRow row = new TableRow()
        .set("tenant_id", tenantId)
        .set("event_id", eventId)
        .set("masked_data", DLPService.mask(c.element().getValue()));
      c.output(row);
    }
  }
}
```

