```python
from google.cloud import asset_v1, bigquery
from google.cloud.asset_v1.types import Asset
from googleapiclient import discovery
from datetime import date
import time

REQUIRED_LABELS = ["env", "cost_center"]
DEFAULT_LABELS = {"env": "untagged", "cost_center": "unknown"}

def audit_and_remediate(project_id):
    client = asset_v1.AssetServiceClient()
    bq_client = bigquery.Client()

    content = client.export_assets(
        request={"parent": f"projects/{project_id}", "asset_types": [
            "compute.googleapis.com/Instance",
            "storage.googleapis.com/Bucket",
            "pubsub.googleapis.com/Topic"
        ]}
    )

    for asset in content.asset_list:
        resource_name = asset.name.split("/")[-1]
        labels = getattr(asset.resource, "labels", {})
        missing = [l for l in REQUIRED_LABELS if l not in labels]

        if missing:
            merged = {**labels, **{l: DEFAULT_LABELS[l] for l in missing}}
            apply_label(asset.asset_type, resource_name, merged)
            log_remediation(bq_client, project_id, resource_name, merged)

def apply_label(asset_type, resource_name, labels):
    retry_count = 0
    while retry_count < 3:
        try:
            if "compute" in asset_type:
                compute = discovery.build("compute", "v1")
                compute.instances().setLabels(
                    project=PROJECT, instance=resource_name,
                    body={"labels": labels, "labelFingerprint": "0"}
                ).execute()
            elif "storage" in asset_type:
                storage = discovery.build("storage", "v1")
                storage.buckets().patch(
                    bucket=resource_name, body={"labels": labels}
                ).execute()
            elif "pubsub" in asset_type:
                pubsub = discovery.build("pubsub", "v1")
                pubsub.projects().topics().patch(
                    name=resource_name, body={"labels": labels}
                ).execute()
            return
        except Exception as e:
            retry_count += 1
            time.sleep(2 ** retry_count)

def log_remediation(bq_client, project_id, resource_id, labels):
    table = bq_client.dataset("remediation_logs").table("label_events")
    insert_id = f"{resource_id}_{date.today().isoformat()}"
    bq_client.insert_rows_json(table, [{
        "insertId": insert_id,
        "projectId": project_id,
        "resourceId": resource_id,
        "labelsApplied": labels,
        "timestamp": bigquery舍 Client().timestamp()
    }])
```

