const { BigQuery } = require('@google-cloud/bigquery');
const { DLP } = require('@google-cloud/dlp');

const bigquery = new BigQuery();
const dlp = new DLP();

const SCHEMA = ['userId', 'event', 'ts'];

async function validateSchema(data) {
  return SCHEMA.every(field => data[field] !== undefined);
}

async function redactPII(data) {
  const item = { stringValue: JSON.stringify(data) };
  const infoTypes = [{ name: 'EMAIL_ADDRESS' }, { name: 'PHONE_NUMBER' }];
  const deidentifyConfig = { infoTypeTransformations: { transformations: [{ infoTypes, primitiveTransformation: { replaceWithInfoTypeConfig: {} } }] } };
  const [result] = await dlp.deidentifyContent({ parent: process.env.PROJECT_ID, item, deidentifyConfig });
  return JSON.parse(result.item.stringValue);
}

exports.onTelemetryRaw = async (message) => {
  const data = JSON.parse(message.data.toString());
  if (!await validateSchema(data)) throw new Error('Invalid schema');
  const sanitized = await redactPII(data);
  const insertId = message.publishTime + '_' + message.messageId;
  await bigquery.dataset('daily_partitioned').table('sanitized_events').insert([{ ...sanitized, insertId }]);
  return { status: 'success' };
};
```

