const {Storage} = require('@google-cloud/storage');
const storage = new Storage();
const SRC = 'ingest-bucket';
const DST = 'dr-bucket';
exports.replicateToDR = async (event, context) => {
  const file = event.name;
  const srcFile = storage.bucket(SRC).file(file);
  // get MD5 from metadata
  const [md] = await srcFile.getMetadata().then(m => [m.md5Hash]);
  const dstFile = storage.bucket(DST).file(file);
  try {
    const [dstMeta] = await dstFile.getMetadata().catch(() => [null]);
    if (dstMeta && dstMeta.md5Hash === md) { return; }
    await srcFile.copy(dstFile);
  } catch (e) {
    // publish to Pub/Sub/log for alerting
    throw e;
  }
};
```

