class DedupDoFn extends DoFn<Event, Event> {
  @StateId("seen") private final StateSpec<ValueState<Boolean>> seen = null;
  @ProcessElement
  public void process(@Element Event e, @StateId("seen") ValueState<Boolean> seen) {
    if (Boolean.FALSE.equals(seen.read())) {
      seen.write(true);
      out.output(e);
    }
  }
}
